function kSum(nums, k) {
    const sums = [0];
    for (const num of nums) {
        if (num > 0) {
            for (let i = sums.length - 1; i >= 0; i--) {
                sums.push(sums[i] + num);
            }
            sums.sort((a, b) => b - a);
        } else {
            sums.push(num);
        }
    }

    return sums[k - 1];
}
